mapper.select:
SELECT `쉼표번호`, email, password, nickname, status, email_verified, role, created_at, updated_at
FROM users
WHERE email = #{email}

SELECT `쉼표번호`, email, password, nickname, status, email_verified, role, created_at, updated_at
FROM users
WHERE nickname = #{nickname}

SELECT `쉼표번호`, email, password, nickname, status, email_verified, role, created_at, updated_at
FROM users
WHERE `쉼표번호` = #{쉼표번호}

SELECT `쉼표번호`, token, verified, expires_at AS expiresAt
FROM email_verification
WHERE token = #{token}

SELECT `쉼표번호`, token, expires_at AS expiresAt, used
FROM password_reset_token
WHERE token = #{token}
